INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/09/22 14:59:59", "2023/06/30 12:00:00", 1.47, 2002, 1, "クローチェ", -470.0, 1, 1, 126401, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", 10001, 0.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/09/22 14:59:59", "2023/06/30 12:00:00", 2.15, 2002, 1, "クローチェ", -470.0, 2, 2, 126401, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", 10002, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/09/22 14:59:59", "2023/06/30 12:00:00", 0.0, 2002, 1, "ライラエル", -470.0, 1, 2, 126501, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", 10003, 0.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/09/22 14:59:59", "2023/06/30 12:00:00", 0.0, 2002, 1, "ライラエル", -470.0, 2, 1, 126501, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", 10004, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/12/22 14:59:59", "2023/09/15 15:00:00", 0.0, 2002, 2, "リンド", -470.0, 1, 2, 127702, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", 10005, 0.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/12/22 14:59:59", "2023/09/15 15:00:00", 0.0, 2002, 2, "リンド", -470.0, 2, 2, 127702, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", 10006, 0.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/12/22 14:59:59", "2023/09/15 15:00:00", 0.0, 2002, 2, "ヴルム", -470.0, 1, 1, 127802, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", 10007, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/12/22 14:59:59", "2023/09/15 15:00:00", 6.5, 2002, 2, "ヴルム", -470.0, 2, 2, 127802, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", 10008, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/03/22 14:59:59", "2023/12/15 15:00:00", 0.0, 2002, 3, "アネモネ", -470.0, 1, 2, 129602, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", 10009, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/03/22 14:59:59", "2023/12/15 15:00:00", 0.0, 2002, 3, "アネモネ", -470.0, 2, 2, 129602, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", 10010, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/03/22 14:59:59", "2023/12/15 15:00:00", 0.0, 2002, 3, "ネフィ=ネラ", -470.0, 1, 1, 129701, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", 10011, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/03/22 14:59:59", "2023/12/15 15:00:00", 6.2, 2002, 3, "ネフィ=ネラ", -470.0, 2, 2, 129701, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", 10012, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/06/22 14:59:59", "2024/03/15 15:00:00", 3.1, 2002, 4, "カノン", -470.0, 1, 3, 130301, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", 10013, 0.0, 5);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/06/22 14:59:59", "2024/03/15 15:00:00", 6.15, 2002, 4, "カノン", -470.0, 2, 3, 130301, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", 10014, 0.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/06/22 14:59:59", "2024/03/15 15:00:00", 0.0, 2002, 4, "ナーナ", -470.0, 1, 2, 130401, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", 10015, 0.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/06/22 14:59:59", "2024/03/15 15:00:00", 3.35, 2002, 4, "ナーナ", -470.0, 2, 2, 130401, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", 10016, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/09/22 14:59:59", "2024/06/15 15:00:00", 0.0, 2002, 5, "ホウオウ", -470.0, 1, 1, 130502, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", 10017, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/09/22 14:59:59", "2024/06/15 15:00:00", 3.18, 2002, 5, "ホウオウ", -470.0, 2, 2, 130502, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", 10018, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/09/22 14:59:59", "2024/06/15 15:00:00", 0.0, 2002, 5, "ホウオウ", -470.0, 3, 4, 130503, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 10019, 0.0, 4);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/09/22 14:59:59", "2024/06/15 15:00:00", 4.9, 2002, 5, "ネア", -470.0, 1, 1, 123301, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", 10020, 0.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/09/22 14:59:59", "2024/06/15 15:00:00", 4.8, 2002, 5, "ネア", -470.0, 2, 1, 123301, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 10021, 0.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/12/22 14:59:59", "2024/09/15 15:00:00", 4.922, 2002, 6, "カリザ", -470.0, 1, 3, 133301, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 10022, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/12/22 14:59:59", "2024/09/15 15:00:00", 9.638, 2002, 6, "カリザ", -470.0, 2, 3, 133301, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 10023, 0.0, 5);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/12/22 14:59:59", "2024/09/15 15:00:00", 2.88, 2002, 6, "ミーア", -470.0, 1, 1, 133401, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 10024, 0.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/12/22 14:59:59", "2024/09/15 15:00:00", 4.818, 2002, 6, "ミーア", -470.0, 2, 5, 133401, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", 10025, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/03/22 14:59:59", "2024/12/15 15:00:00", 1.78, 2002, 7, "グレイス", -470.0, 1, 2, 133002, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", 10026, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/03/22 14:59:59", "2024/12/15 15:00:00", 6.15, 2002, 7, "グレイス", -470.0, 2, 1, 133002, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", 10027, 0.0, 7);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/03/22 14:59:59", "2024/12/15 15:00:00", 4.28, 2002, 7, "ヴァイオレット", -470.0, 1, 6, 133102, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", 10028, 0.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/03/22 14:59:59", "2024/12/15 15:00:00", 0.0, 2002, 7, "ヴァイオレット", -470.0, 2, 1, 133102, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", 10029, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/06/23 14:59:59", "2025/03/15 15:00:00", 5.53, 2002, 8, "ルルィ", -470.0, 1, 2, 136902, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", 10030, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/06/23 14:59:59", "2025/03/15 15:00:00", 6.05, 2002, 8, "ルルィ", -470.0, 2, 9, 136902, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", 10031, 0.0, 7);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/06/23 14:59:59", "2025/03/15 15:00:00", 0.0, 2002, 8, "デュラン", -470.0, 1, 2, 137001, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", 10032, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/06/23 14:59:59", "2025/03/15 15:00:00", 0.0, 2002, 8, "デュラン", -470.0, 2, 2, 137001, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 10033, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/09/23 14:59:59", "2025/06/16 15:00:00", 0.0, 2002, 9, "サツキ", -470.0, 1, 2, 135902, "おう\n好きなもん持ってきな", 10034, 0.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/09/23 14:59:59", "2025/06/16 15:00:00", 4.935, 2002, 9, "サツキ", -470.0, 2, 1, 135902, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 10035, 0.0, 6);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/09/23 14:59:59", "2025/06/16 15:00:00", 7.441, 2002, 9, "ユキノ", -470.0, 1, 2, 135802, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 10036, 0.0, 5);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/09/23 14:59:59", "2025/06/16 15:00:00", 0.0, 2002, 9, "ユキノ", -470.0, 2, 7, 135802, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 10037, 0.0, 7);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/12/22 14:59:59", "2025/09/16 15:00:00", 2.295, 2002, 10, "クルル", -470.0, 1, 2, 130901, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 10038, 0.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/12/22 14:59:59", "2025/09/16 15:00:00", 6.281, 2002, 10, "クルル", -470.0, 2, 1, 130901, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 10039, 0.0, 6);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/12/22 14:59:59", "2025/09/16 15:00:00", 5.549, 2002, 10, "ヴォルガーノ", -470.0, 1, 2, 137701, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 10040, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/12/22 14:59:59", "2025/09/16 15:00:00", 2.64, 2002, 10, "ヴォルガーノ", -470.0, 2, 3, 137701, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 10041, 0.0, 6);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/03/23 11:59:59", "2025/12/15 15:00:00", 7.642, 2002, 11, "ライラエル", -470.0, 1, 7, 132801, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 10042, 0.0, 4);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/03/23 11:59:59", "2025/12/15 15:00:00", 0.0, 2002, 11, "ライラエル", -470.0, 2, 1, 132802, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 10043, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/03/23 11:59:59", "2025/12/15 15:00:00", 0.0, 2002, 11, "クローチェ", -470.0, 1, 1, 134502, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 10044, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/03/23 11:59:59", "2025/12/15 15:00:00", 3.72, 2002, 11, "クローチェ", -470.0, 2, 2, 134501, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 10045, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/06/22 11:59:59", "2026/03/16 12:00:00", 4.991, 2002, 12, "ネフィ＝ネラ", -470.0, 1, 2, 138201, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", 10046, 0.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/06/22 11:59:59", "2026/03/16 12:00:00", 3.877, 2002, 12, "ネフィ＝ネラ", -470.0, 2, 1, 138201, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", 10047, 0.0, 4);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/06/22 11:59:59", "2026/03/16 12:00:00", 1.71, 2002, 12, "アラクネ", -470.0, 1, 4, 136001, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", 10048, 0.0, 6);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/06/22 11:59:59", "2026/03/16 12:00:00", 5.32, 2002, 12, "アラクネ", -470.0, 2, 5, 136001, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", 10049, 0.0, 2);
